import {
  isPresentationLockedByEngagementLimits,
  useEngagementLimits,
} from '@mentimeter/paywalls-data-hooks';
import {
  useActiveQuestionId,
  useActiveSeriesId,
} from '@mentimeter/__app-split-lib/core/use-ids';
import { ErrorBoundary } from '@mentimeter/errors/ErrorBoundary';
import {
  EditorFlags,
  useEditorFlag,
  useSelectedSlideIds,
  useUserPresentationRole,
} from '@mentimeter/core-global-state';
import {
  questionsCacheKey,
  seriesCacheKey,
  useQuestionIdsHaveResults,
} from '@mentimeter/core-hooks';
import {
  useEditorDuplicateQuestions,
  useEditorQuestions,
  useEditorSeries,
} from '@mentimeter/editor-data-hooks';
import { useEditorRouter } from '@mentimeter/editor-essentials/hooks';
import { useKeyboardHandler } from '@mentimeter/editor-essentials/utils';
import { JumpToSlide, OverviewList } from '@mentimeter/editor-overview-ui';
import {
  getQuestionBySlidePublicKey,
  useEditorPresenceNotifier,
  useEditorSomeonePresenting,
} from '@mentimeter/editor-realtime';
import {
  trackDuplicatedSlides,
  trackTriggeredContextMenuButton,
  trackTriggeredContextMenuMouse,
  trackClickedCommentIcon,
} from '@mentimeter/editor-tracking';
import { useDeviceChecker } from '@mentimeter/ragnar-device';
import { useOutsideClick } from '@mentimeter/react-hooks';
import { TrackingContext } from '@mentimeter/http-clients';
import { useUser } from '@mentimeter/user';
import { useActiveSidebarPaneStore } from '@mentimeter/editor-state';
import {
  Suspense,
  useCallback,
  useEffect,
  useMemo,
  useState,
  useRef,
  type RefObject,
} from 'react';
import { useToast } from '@mentimeter/toast';
import { CopyPasteDataHandler } from './CopyPasteDataHandler';
import { OverviewListItemDataHandler } from './OverviewListItemDataHandler';
import { useOverviewMoveQuestions } from './use-overview-move-questions';
import { useOverviewSkipQuestions } from './use-overview-skip-questions';

const emptyArray = [] as const;

const findIndexOfById = <T extends { id: string }>(
  items: Array<T> | undefined,
  id: string | undefined,
): number => {
  return items?.findIndex((item) => item.id === id) ?? -1;
};

export const OverviewListDataHandler = ({
  slidePublicKey,
  onAddSlide,
  onClickSlideThumbnail,
}: {
  slidePublicKey: string;
  onAddSlide: (questionId: string) => void;
  onClickSlideThumbnail: (questionId: string) => void;
}) => {
  const { navigateToSlide } = useEditorRouter();

  const [, setActiveSidebarPane] = useActiveSidebarPaneStore();
  const seriesId = useActiveSeriesId();
  const activeQuestionId = useActiveQuestionId();
  const { questions, lazyGetQuestions } = useEditorQuestions(seriesId, {
    getQuestionsCacheKey: questionsCacheKey,
  });

  const userRole = useUserPresentationRole();

  const { series } = useEditorSeries(seriesId, {
    getSeriesCacheKey: seriesCacheKey,
  });
  const overviewSkipQuestions = useOverviewSkipQuestions({
    seriesId,
    userRole,
    currentQuestionId: activeQuestionId,
    setCurrentQuestion: navigateToSlide,
  });

  const skipQuestions = useCallback(
    (questionIds: string[], skip: boolean) => {
      const questions = lazyGetQuestions();
      if (questions) {
        overviewSkipQuestions(questionIds, questions, skip);
      }
    },
    [lazyGetQuestions, overviewSkipQuestions],
  );

  const moveQuestions = useOverviewMoveQuestions({
    seriesId,
    userRole,
    getSeriesCacheKey: seriesCacheKey,
    getQuestionsCacheKey: questionsCacheKey,
  });
  const [newPresentationMode] = useEditorFlag(EditorFlags.NewPresentationMode);

  const [isDuplicatingSlides, setIsDuplicatingSlides] =
    useState<boolean>(false);

  const duplicateQuestions = useEditorDuplicateQuestions(
    seriesId,
    questionsCacheKey,
  );

  const toast = useToast();

  const { user } = useUser();
  const [selectedSlideIds, setSelectedSlideIds] = useSelectedSlideIds();
  const { disable: onDisableKeyboardNavigation } = useKeyboardHandler();
  const [contextMenuQuestionId, setContextMenuQuestionId] =
    useState<string>(activeQuestionId);
  const [menuVisibilityByQuestion, setMenuVisibilityByQuestion] = useState<
    Record<string, boolean>
  >({});
  const [questionAddMode] = useEditorFlag(EditorFlags.QuestionAddMode);

  const isMenuVisible = Boolean(
    menuVisibilityByQuestion[contextMenuQuestionId],
  );

  const setQuestionOpenState = useCallback(
    (questionId: string, open: boolean) => {
      setMenuVisibilityByQuestion((state) => ({
        ...state,
        [questionId]: open,
      }));
    },
    [setMenuVisibilityByQuestion],
  );

  const { isSmallDevice: mobile } = useDeviceChecker();

  const activeQuestionIndex =
    questions?.findIndex((q) => q.id === activeQuestionId) || 0;

  const handleDuplicateQuestions = useCallback(
    async (questionList: string[]) => {
      const questions = lazyGetQuestions();
      if (questions) {
        // This is a necessary evil because we have no idea what the new duplicated ID's are
        setSelectedSlideIds([]);
        setIsDuplicatingSlides(true);
        try {
          const nextActiveQuestionId = await duplicateQuestions({
            questionsToCopyIds: questionList,
            currentQuestions: questions,
          });

          if (nextActiveQuestionId) {
            navigateToSlide(nextActiveQuestionId);
          }
        } catch (error) {
          if (error instanceof Error) {
            toast.displayToast({
              description: error.message,
              autoDismiss: true,
            });
          }
        } finally {
          setIsDuplicatingSlides(false);
        }

        trackDuplicatedSlides({
          role: userRole,
          amount: questionList.length,
          total: questions?.length ?? 0,
        });
      }
    },
    [
      duplicateQuestions,
      lazyGetQuestions,
      navigateToSlide,
      setSelectedSlideIds,
      toast,
      userRole,
    ],
  );

  const selectRangeOfQuestions = useCallback(
    (questionId: string) => {
      const questions = lazyGetQuestions();
      const indexOfSlide = findIndexOfById(questions, questionId);
      if (questions && indexOfSlide > activeQuestionIndex) {
        setSelectedSlideIds(
          questions
            .slice(activeQuestionIndex, indexOfSlide + 1)
            .map((q) => q.id),
        );
      } else if (questions && indexOfSlide < activeQuestionIndex) {
        setSelectedSlideIds(
          questions
            .slice(indexOfSlide, activeQuestionIndex + 1)
            .map((q) => q.id),
        );
        navigateToSlide(questionId);
      } else {
        // This is a quick fix for selecting just the active slide (contracting the range to one)
        setSelectedSlideIds([questionId]);
      }
    },
    [
      navigateToSlide,
      activeQuestionIndex,
      lazyGetQuestions,
      setSelectedSlideIds,
    ],
  );

  const selectSingleQuestion = useCallback(
    (questionId: string) => {
      const questions = lazyGetQuestions();
      // We don't support unselecting the active question
      if (questionId === activeQuestionId) {
        setSelectedSlideIds([activeQuestionId]);
        return;
      }
      setSelectedSlideIds((state) => {
        const list = [...state];
        // If the question is selected already we remove it
        if (list.indexOf(questionId) > -1) {
          return list.filter((q) => q !== questionId);
        }
        list.push(questionId);
        return list.sort((a, b) => {
          return findIndexOfById(questions, a) - findIndexOfById(questions, b);
        });
      });
    },
    [activeQuestionId, lazyGetQuestions, setSelectedSlideIds],
  );

  const onNotifyPresence = useEditorPresenceNotifier(user);

  useEffect(() => {
    if (activeQuestionId) {
      onNotifyPresence('/series/question/:questionId*', activeQuestionId);
    }
  }, [activeQuestionId, onNotifyPresence]);

  useEffect(() => {
    if (
      activeQuestionId &&
      !questionAddMode &&
      !selectedSlideIds.includes(activeQuestionId)
    ) {
      setSelectedSlideIds([activeQuestionId]);
    }
  }, [
    selectedSlideIds,
    questionAddMode,
    activeQuestionId,
    setSelectedSlideIds,
  ]);

  const outsideClick = (event: MouseEvent) => {
    if (isMenuVisible || selectedSlideIds.length <= 1) {
      // If the context menu is open it will be closed, and we don't want to deselect any slides then
      return;
    }
    // Because the prompts live outside the DOM node wrapping everything we need to check if the event is within one
    const container = document.getElementById('placement-portal');
    if (container && container.contains(event.target as Node)) {
      return;
    }

    if (activeQuestionId) {
      setSelectedSlideIds([activeQuestionId]);
    }
  };

  useOutsideClick(
    ['#editor-overview-list', '#editor-overview-menu'],
    outsideClick,
  );

  const [isSomeonePresenting, presenter] = useEditorSomeonePresenting();
  const { goToPresentationView } = useEditorRouter();

  const engagementLimits = useEngagementLimits();

  const lockedOutOfPresenting = isPresentationLockedByEngagementLimits(
    seriesId,
    engagementLimits,
  );

  const lastPresentedQuestion = getQuestionBySlidePublicKey(
    questions,
    slidePublicKey,
  );

  const presentDisabled =
    newPresentationMode || !questions?.length || lockedOutOfPresenting;

  const questionIds = useMemo(() => {
    const inSelection = selectedSlideIds.includes(contextMenuQuestionId);
    return inSelection ? selectedSlideIds : [contextMenuQuestionId];
  }, [contextMenuQuestionId, selectedSlideIds]);

  const selectedQuestionsHaveResults = Boolean(
    useQuestionIdsHaveResults(
      seriesId,
      questionIds,
      !isMenuVisible || questionIds.length === 0,
    ).data?.has_results,
  );

  const handleContextMenuOpen = useCallback(
    (itemId: string) => {
      setContextMenuQuestionId(itemId);
      trackTriggeredContextMenuMouse({
        role: userRole,
      });
    },
    [userRole],
  );

  const handleDropdownMenuOpen = useCallback(
    (itemId: string) => {
      setContextMenuQuestionId(itemId);
      trackTriggeredContextMenuButton({
        role: userRole,
      });
    },
    [userRole],
  );

  const handleListItemUnskip = useCallback(
    (questionId: string) => {
      skipQuestions([questionId], false);
    },
    [skipQuestions],
  );

  const handleListItemClick = useCallback(
    (event: React.MouseEvent<HTMLElement>, itemId: string) => {
      if (event.nativeEvent.metaKey) {
        selectSingleQuestion(itemId);
      } else if (event.nativeEvent.shiftKey) {
        selectRangeOfQuestions(itemId);
      } else {
        onClickSlideThumbnail(itemId);
        navigateToSlide(itemId);
      }
    },
    [
      navigateToSlide,
      selectRangeOfQuestions,
      selectSingleQuestion,
      onClickSlideThumbnail,
    ],
  );

  const handleContextMenuOpenChange = useCallback(
    (itemId: string, open: boolean) => {
      setQuestionOpenState(itemId, open);
      if (open) {
        handleContextMenuOpen(itemId);
      }
    },
    [handleContextMenuOpen, setQuestionOpenState],
  );

  const listRef = useRef<HTMLOListElement>(null);
  if (!series) {
    return null;
  }

  const handleItemFocus = (itemRef: RefObject<HTMLDivElement | null>) => {
    const list = listRef.current;
    const item = itemRef.current;
    if (!list || !item) return;

    const listHeight = list.clientHeight;
    const listScrollTop = list.scrollTop;
    const itemHeight = item.clientHeight;
    const itemTop = item.offsetTop;
    const distanceFromTop = itemTop - listScrollTop;
    const distanceFromBottom = listHeight - (distanceFromTop + itemHeight);
    const scrollThreshold = itemHeight / 3;
    const itemMarginBottom = 16;

    // We always want the focused item to be fully visible
    // with some extra margin so the next item is loaded in.
    // This ensures all items are reachable via keyboard despite hidden items not being rendered
    const shouldScrollUp = distanceFromTop < scrollThreshold + itemMarginBottom;
    const shouldScrollDown = distanceFromBottom < scrollThreshold;

    if (shouldScrollUp) {
      list.scrollTo({
        top:
          listScrollTop -
          (scrollThreshold + itemMarginBottom - distanceFromTop),
        behavior: 'smooth',
      });
    }
    if (shouldScrollDown) {
      list.scrollTo({
        top: listScrollTop + (scrollThreshold - distanceFromBottom),
        behavior: 'smooth',
      });
    }
  };

  return (
    <>
      <OverviewList
        ref={listRef}
        seriesBgColor={series.theme.background_color}
        seriesTextColor={series.theme.text_color}
        items={questions ?? emptyArray}
        selectedItemsIds={selectedSlideIds}
        activeItemId={activeQuestionId}
        isDragDisabled={questionAddMode}
        onDisableKeyboardNavigation={onDisableKeyboardNavigation}
        onDragEnd={(ids, index) => moveQuestions(ids, index)}
        renderItem={({
          item,
          selected,
          active,
          index,
          isDragging,
          isDraggedElement,
          listeners,
          attributes,
          setNodeRef,
          style,
        }) => {
          const isLastPresentedQuestion =
            series.pace.mode === 'presenter' &&
            lastPresentedQuestion?.id === item.id;

          return (
            <OverviewListItemDataHandler
              key={item.id}
              active={active}
              index={index}
              isDragging={isDragging}
              isDraggedElement={isDraggedElement}
              isSomeonePresenting={isSomeonePresenting}
              item={item}
              mobile={mobile}
              onClick={handleListItemClick}
              onDropdownMenuOpen={handleDropdownMenuOpen}
              onStartPresenting={goToPresentationView}
              onContextMenuOpenChange={handleContextMenuOpenChange}
              onDropdownOpenChange={setQuestionOpenState}
              onUnskip={handleListItemUnskip}
              onAddSlide={onAddSlide}
              presenterName={presenter?.name}
              selected={selected}
              showPlayButton={!presentDisabled && isLastPresentedQuestion}
              theme={series.theme}
              contextMenuQuestionId={contextMenuQuestionId}
              onDuplicateQuestions={handleDuplicateQuestions}
              isDuplicatingSlides={isDuplicatingSlides}
              selectedQuestionsHaveResults={selectedQuestionsHaveResults}
              listeners={listeners}
              style={style}
              setNodeRef={setNodeRef}
              attributes={attributes}
              onFocus={handleItemFocus}
              onClickCommentIcon={() => {
                setActiveSidebarPane('comments');
                trackClickedCommentIcon({
                  role: 'Collaborator',
                  context: TrackingContext.Editview,
                  seriesId: series.id,
                  isSharedPresentation: series.co_edited,
                  hasResults: series.has_results,
                  permission:
                    series.owner_id === user?.id ? 'Owner' : 'Collaborator',
                });
              }}
            />
          );
        }}
      />
      {!isDuplicatingSlides ? (
        <ErrorBoundary
          feature="creation-experience"
          errorMessage="Could not load Overview CopyPasteContainer"
        >
          <Suspense fallback={null}>
            <CopyPasteDataHandler />
          </Suspense>
        </ErrorBoundary>
      ) : null}
      {!mobile ? (
        <JumpToSlide
          getQuestionByIndex={(index: number) => questions?.[index]}
          selectQuestion={(questionId, rangeSelection) => {
            if (rangeSelection) {
              selectRangeOfQuestions(questionId);
            } else {
              selectSingleQuestion(questionId);
            }
          }}
          openQuestion={navigateToSlide}
        />
      ) : null}
    </>
  );
};
