  ];
  const preloadedState = {
    questions,
    presentation: {
      isAuthorized: true,
      isEmbedded: false,
      showEndStatus: false,
    };

    // Create the Redux store with middleware
    const store = configureStore({
      reducer: combineReducers({
        quiz: emptyReducer,
        questions: emptyReducer,
        presentation: emptyReducer,
      }),
      preloadedState,
      middleware: (getDefaultMiddleware) =>
        getDefaultMiddleware({
          thunk: true,
          serializableCheck: false,
          immutableCheck: false,
        }).concat(actionMiddleware, listenerMiddleware),
    });

    return <ReduxProvider store={store}>{children}</ReduxProvider>;
};

const setupProviders = (children: ReactNode) => {
  return (
    <CoreHooksProvider
      device_id="123"
      seriesId="123"
      shouldSubscribe={false}
    >
      <KeyboardHandlerProvider
        questionIds={[]}
        activeQuestionIndex={0}
        activateQuestion={(questionId: string) => {
          // navigateToSlide(questionId);
        }}
      >
        <PresenceConfigContext.Provider
          value={{
            actor: 'editor',
            seriesId: '123',
            shouldUsePresence: false,
          }}
        >
