const setupHttpClient = () => {
  setupHttp({
    core: {
      defaultRegion: 'eu',
      baseUrls: {
        eu: 'test',
      },
      createClient() {
        return {
          series: {
            get: fn().mockImplementation(() => ({
              data: mockSeries,
            })),
          },
        } as any;
      },
    },
  });
};
```

2. Refactor the decorators in the story file to use the extracted functions:

```tsx
decorators: [
  (Story) => {
    setupReduxProvider();
    setupHttpClient();
    return setupProviders(<Story />);
  },
],
```

By refactoring the decorators in this way, you can make the code cleaner, easier to understand, and more modular. Additionally, it allows you to reuse the setup logic in other stories if needed.
